            }
            if (Configuration.getAttributeAsBoolean(ConfigAttribute.USER_MENUACT)
                            && UUID.fromString(Configuration.getAttribute(ConfigAttribute.USER_MENUMENU)).equals(
                                            getCommandUUID())) {
                for (final String key : UsageRegistry.getKeyList()) {
